func Test_ResultTablesEmptyWhenNoTables(t *testing.T) {
	// Result tables array is empty when input has no tables
	var options htmd.ConversionOptions
	if err := json.Unmarshal([]byte(`{"include_document_structure":true}`), &options); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := htmd.Convert(`<p>No tables here</p>`, &options)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if result.Content == nil {
		t.Errorf("expected non-empty value")
	}
	assert.Equal(t, len(result.Tables), 0, "expected exactly 0 elements")
}

func Test_ResultTablesMultiple(t *testing.T) {
	// Multiple tables each appear in the tables array
	var options htmd.ConversionOptions
	if err := json.Unmarshal([]byte(`{"include_document_structure":true}`), &options); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := htmd.Convert(`<table><tr><th>A</th></tr><tr><td>1</td></tr></table><p>Between</p><table><tr><th>B</th></tr><tr><td>2</td></tr></table>`, &options)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	assert.GreaterOrEqual(t, len(result.Tables), 2, "expected at least 2 elements")
}

